const TYPES = ['micro_lesson', 'quiz', 'guided_practice', 'visual_summary', 'micro_lesson', 'micro_lesson', 'quiz', 'micro_lesson'];
const DIFFICULTIES = ['beginner', 'beginner', 'intermediate', 'intermediate', 'intermediate', 'beginner', 'beginner', 'intermediate'];

// Chapters per subject → lesson count
const LESSON_COUNTS = {
  algebra: [8, 8, 8],           // 24
  biology: [8, 8, 8],           // 24
  world_history: [8, 8, 8],     // 24
  english: [8, 8, 8],           // 24
  chemistry: [7, 7, 7],        // 21
  geometry: [7, 7, 7],         // 21
  us_history: [7, 7, 7],       // 21
  physics: [7, 7, 7],          // 21
  psychology: [10, 10],        // 20
};
// Total: 200

const QUIZ_OPTIONS_POOL = {
  micro_lesson: [
    { options: ['Understanding the core concept helps solve related problems', 'Memorizing formulas is enough', 'Skipping the basics is fine', 'Only practice problems matter'], correct: 0 },
    { options: ['By breaking problems into smaller steps', 'By guessing the answer', 'By working faster', 'By avoiding difficult parts'], correct: 0 },
    { options: ['Applying the method to similar situations', 'Reading the explanation once', 'Watching a video', 'Taking notes without review'], correct: 0 },
    { options: ['Practice and review over time', 'Cramming the night before', 'Reading the same page repeatedly', 'Listening to a lecture once'], correct: 0 },
  ],
  quiz: [
    { options: ['Check your work by reviewing each step', 'Assume you are correct', 'Ask someone to check for you', 'Skip the verification step'], correct: 0 },
    { options: ['To identify areas that need more practice', 'To get a grade only', 'To compare with others', 'To finish the assignment'], correct: 0 },
    { options: ['Take a break and come back later', 'Give up on that question', 'Guess randomly', 'Skip the entire test'], correct: 0 },
    { options: ['Reading the question carefully before answering', 'Answering as fast as possible', 'Leaving difficult questions blank', 'Changing answers randomly'], correct: 0 },
  ],
  guided_practice: [
    { options: ['By following the steps in order', 'By skipping to the end', 'By memorizing the answer', 'By using a calculator only'], correct: 0 },
    { options: ['Apply what you learned to new situations', 'Repeat the same problem again', 'Move to the next topic immediately', 'Close the book'], correct: 0 },
    { options: ['Check your work against the solution', 'Assume you are right', 'Submit without checking', 'Ask for the answer'], correct: 0 },
    { options: ['Identify where you made a mistake', 'Ignore the mistake', 'Start over from the beginning', 'Blame the instructions'], correct: 0 },
  ],
  visual_summary: [
    { options: ['A clear overview that connects ideas', 'A list of random facts', 'A page full of text', 'A collection of quotes'], correct: 0 },
    { options: ['They show relationships between concepts', 'They are just decorations', 'They replace all text', 'They are only for children'], correct: 0 },
    { options: ['By organizing information visually', 'By making things colorful', 'By adding more details', 'By removing all text'], correct: 0 },
    { options: ['The main ideas and how they connect', 'Every small detail', 'The opinions of others', 'Only the dates and names'], correct: 0 },
  ],
};

function slug(text) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
}

function pickRandom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function generate() {
  const lessons = [];
  const videos = [];
  let lessonNum = 1;

  for (const subject of SUBJECTS) {
    const subjChapters = CHAPTERS.filter(c => c.subjectId === subject.id);
    const counts = LESSON_COUNTS[subject.id];

    subjChapters.forEach((chapter, chIdx) => {
      const chapterKey = chapter.id;
      const bodies = BODIES[chapterKey] || ['No content available for this topic.'];
      const count = counts[chIdx];

      for (let i = 0; i < count; i++) {
        const typeIdx = i % TYPES.length;
        const contentType = TYPES[typeIdx];
        const difficulty = DIFFICULTIES[typeIdx];
        const lessonId = `${chapterKey}_${i + 1}`;
        const bodyText = bodies[i % bodies.length];

        const titlePrefixes = {
          micro_lesson: ['Introduction to', 'Understanding', 'Mastering', 'A Complete Guide to', 'Deep Dive into', 'Exploring'],
          quiz: ['Quick Quiz:', 'Test Your Knowledge:', 'Check Your Understanding:', 'Practice Questions:'],
          guided_practice: ['Practice:', 'Hands-On:', 'Exercise:', 'Step by Step:'],
          visual_summary: ['Visual Summary:', 'At a Glance:', 'Overview:', 'Key Concepts:'],
        };

        const prefixes = titlePrefixes[contentType] || ['About'];
        const topicWords = chapter.title.split(' ').slice(0, 3).join(' ');
        const title = `${pickRandom(prefixes)} ${topicWords}` + (i > 0 ? ` (Part ${i + 1})` : '');

        const quizPool = QUIZ_OPTIONS_POOL[contentType] || QUIZ_OPTIONS_POOL.micro_lesson;
        const q = quizPool[i % quizPool.length];

        const flashcardCount = contentType === 'flashcard_collection' ? 4 : (contentType === 'micro_lesson' || contentType === 'visual_summary' ? 2 : 1);
        const flashcards = [];
        const bodyLines = bodyText.split('\n').filter(l => l.trim().length > 20);
        for (let f = 0; f < flashcardCount && f < bodyLines.length; f++) {
          const line = bodyLines[f].replace(/^[•\-\d\.\s]+/, '').trim();
          if (line.length > 10 && line.length < 200) {
            flashcards.push({
              id: `fc_${lessonId}_${f + 1}`,
              title: `Key Point ${f + 1}`,
              contentType: 'flashcard',
              description: '',
              difficulty: 'beginner',
              estimatedDurationSeconds: 300,
              tags: [],
              body: line,
              subject: '',
              chapter: '',
              metadata: {},
              quizOptions: [],
              correctOptionIndex: null,
              flashcards: [],
            });
          }
        }

        // Create a video for roughly every 5th lesson
        let videoId = null;
        if (i % 5 === 0) {
          videoId = `vid_${lessonId}`;
          const videoUrl = VIDEO_URLS[videos.length % VIDEO_URLS.length];
          videos.push({
            id: videoId,
            linkedLessonId: lessonId,
            title: `${subject.name}: ${chapter.title} — Video ${Math.floor(i / 5) + 1}`,
            description: `A visual exploration of ${chapter.title.toLowerCase()} concepts in ${subject.name}.`,
            duration: `${4 + (i % 3)}:${30 * (i % 2)}`.replace(':0', ':00'),
            durationSeconds: 240 + (i % 3) * 30,
            subject: subject.name,
            chapter: chapter.title,
            difficulty: difficulty,
            assetPath: videoUrl,
            keyPoints: bodyLines.slice(0, 4).map(l => l.replace(/^[•\-\d\.\s]+/, '').trim()).filter(l => l.length > 5 && l.length < 150),
            chapters: bodyLines.slice(0, 5).map((l, idx) => `${idx * 0.5}:00 — ${l.replace(/^[•\-\d\.\s]+/, '').trim().slice(0, 50)}`),
          });
        }

        const tags = [subject.name.toLowerCase(), chapter.title.toLowerCase().split(' ')[0].toLowerCase(), contentType === 'quiz' ? 'quiz' : 'lesson'];
        if (difficulty === 'beginner') tags.push('beginner');
        if (difficulty === 'intermediate') tags.push('intermediate');

        lessons.push({
          id: lessonId,
          title: title,
          description: `Learn about ${chapter.title.toLowerCase()} in ${subject.name}.`,
          contentType: contentType,
          difficulty: difficulty,
          estimatedDurationSeconds: 300 + (i % 5) * 60,
          tags: tags,
          body: bodyText,
          subject: subject.name,
          chapter: chapter.title,
          metadata: {},
          quizOptions: q.options,
          correctOptionIndex: q.correct,
          flashcards: flashcards,
          videoId: videoId,
          chapterId: chapter.id,
        });

        lessonNum++;
      }
    });
  }

  console.error(`Generated ${lessons.length} lessons and ${videos.length} videos.`);
  return { lessons, videos };
}

function main() {
  const { lessons, videos } = generate();
  const assetsDir = path.join(__dirname, '..', 'assets', 'content');

  // Write lessons.json
  fs.writeFileSync(path.join(assetsDir, 'lessons.json'), JSON.stringify(lessons, null, 2));
  console.error(`Written lessons.json (${lessons.length} lessons)`);

  // Write videos.json
  fs.writeFileSync(path.join(assetsDir, 'videos.json'), JSON.stringify(videos, null, 2));
  console.error(`Written videos.json (${videos.length} videos)`);

  // Write subjects.json
  fs.writeFileSync(path.join(assetsDir, 'subjects.json'), JSON.stringify(SUBJECTS, null, 2));
  console.error(`Written subjects.json (${SUBJECTS.length} subjects)`);

  // Write chapters.json
  fs.writeFileSync(path.join(assetsDir, 'chapters.json'), JSON.stringify(CHAPTERS, null, 2));
  console.error(`Written chapters.json (${CHAPTERS.length} chapters)`);

  // Summary
  console.error('');
  console.error('========== LESSON DISTRIBUTION ==========');
  const subjectCounts = {};
  for (const l of lessons) {
    subjectCounts[l.subject] = (subjectCounts[l.subject] || 0) + 1;
  }
  for (const [s, c] of Object.entries(subjectCounts)) {
    console.error(`${s}: ${c} lessons`);
  }
  console.error(`Total: ${lessons.length} lessons`);
  console.error(`Total videos: ${videos.length}`);
}

main();
